-- ============================================
-- Legislacao full-site: jhc / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/178842
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 47
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=178842, tipo Deputado(a), ordemAssinatura=1.
-- 53 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'jhc';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'jhc: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao jhc: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2250357', '2246495', '2246496', '2245884', '2257495', '2256263', '2241869', '2263099', '2256272', '2254548', '2251631', '2263113', '2261298', '2257931', '2255853', '2254943', '2252713', '2253688', '2252270', '2248322', '2246114', '2242373', '2241870', '2239121', '2234146', '2225405', '2221816', '2251632', '2245885', '2225404', '2220672', '2246337', '2242596', '2239475', '2237003', '2226077', '2238474', '2226801', '2223836', '2257292', '2252603', '2242352', '2239476', '2255544', '2250337', '2241871', '2257637');
  IF target_present <> 47 THEN
    RAISE EXCEPTION 'Pre-condicao jhc: esperadas 47 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2250357', '2246495', '2246496', '2245884', '2257495', '2256263', '2241869', '2263099', '2256272', '2254548', '2251631', '2263113', '2261298', '2257931', '2255853', '2254943', '2252713', '2253688', '2252270', '2248322', '2246114', '2242373', '2241870', '2239121', '2234146', '2225405', '2221816', '2251632', '2245885', '2225404', '2220672', '2246337', '2242596', '2239475', '2237003', '2226077', '2238474', '2226801', '2223836', '2257292', '2252603', '2242352', '2239476', '2255544', '2250337', '2241871', '2257637')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'jhc-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao jhc: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao jhc: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

